import React from "react"
import { properties } from '../../properties/properties.js'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'


class EvalCreated extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0
        };
    }




        componentDidMount() {


            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = properties.backend + `evalcreated`

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                this.setState({results: response})
                this.setState({screen: 1})

              })
              .catch(err => {
                console.log(err);
              });

        }




          render() {


            var header = "Loading ..."


            if (this.state.screen === 1) {
              header = ""
              var content = []

              //console.log(this.state.results.complete)
              //console.log(this.state.results.error)
              //console.log(this.state.results.incomplete)


              var paddingSize = "8px"
              var i = 0

                var created = []
                created.push(<tr><td style={{padding: paddingSize}}>Date</td><td style={{padding: paddingSize}}>Evaluator</td><td style={{padding: paddingSize}}>Evaluatee</td><td style={{padding: paddingSize}}>Eval</td><td style={{padding: paddingSize}}>Program</td></tr>)
                this.state.results.created.map(rec => {
                        var bgcolor = "#FAFAFA"
                        if (i%2 == 0) {
                            bgcolor = "#F4F4F4"
                        }
                        created.push(<tr style={{backgroundColor: bgcolor}}><td style={{padding: paddingSize}}>{rec.date}</td><td style={{padding: paddingSize}}>{rec.evaluator}</td><td style={{padding: paddingSize}}>{rec.evaluatee}</td><td style={{padding: paddingSize}}>{rec.eval_name}</td><td style={{padding: paddingSize}}>{rec.program}</td></tr>)
                        i += 1
                    }
                )


                i = 0

                var notcreated = []
                notcreatedcreated.push(<tr><td style={{padding: paddingSize}}>Date</td><td style={{padding: paddingSize}}>Evaluator</td><td style={{padding: paddingSize}}>Evaluatee</td><td style={{padding: paddingSize}}>Eval</td><td style={{padding: paddingSize}}>Program</td></tr>)
                this.state.results.notcreated.map(rec => {
                        var bgcolor = "#FAFAFA"
                        if (i%2 == 0) {
                            bgcolor = "#F4F4F4"
                        }
                        notcreated.push(<tr style={{backgroundColor: bgcolor}}><td style={{padding: paddingSize}}>{rec.date}</td><td style={{padding: paddingSize}}>{rec.evaluator}</td><td style={{padding: paddingSize}}>{rec.evaluatee}</td><td style={{padding: paddingSize}}>{rec.eval_name}</td><td style={{padding: paddingSize}}>{rec.program}</td></tr>)
                        i += 1
                    }
                )



              content.push(<Tabs>
                <TabList>
                    <Tab>Created</Tab>
                    <Tab>Not Created</Tab>
                </TabList>
                <TabPanel><div >
                    <table>{created}</table>
                    </div></TabPanel>
                <TabPanel><div >   <table>{notcreated}</table></div></TabPanel>
            </Tabs>)

            }



            return (
                <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default EvalCreated
